function searchFilter(e,t){var r,l,a,n;for(r=document.getElementById(e).value.toUpperCase(),l=document.getElementById(t).getElementsByTagName("tr"),n=0;n<l.length;n++)(a=l[n].getElementsByTagName("td")[1])&&(a.innerHTML.toUpperCase().indexOf(r)>-1?l[n].style.display="":l[n].style.display="none")}document.querySelectorAll(".close-filter").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault(),document.querySelector(".search__filter-properties").classList.toggle("active")})}),document.querySelector("#searchOrder").addEventListener("keyup",()=>{searchFilter("searchOrder","tableOrder")});